`,a.jsx(e.p,{children:a.jsx(e.strong,{children:"O que é pré-autorização?"})}),`
`,a.jsx(e.p,{children:"Pré-autorização é uma etapa opcional que bloqueia um valor no cartão sem consumi-lo. Usada em hotéis, aluguel de carros e combustível. O valor é capturado ou liberado depois, conforme o uso real."}),`
`,a.jsx(e.p,{children:a.jsx(e.strong,{children:"O que é NSU?"})}),`
`,a.jsx(e.p,{children:"NSU (Número de Documento Único) é o identificador único de uma transação junto à bandeira. Aparece no comprovante e serve para referência em consultas, ajustes e disputas. Diferente do código de autorização, que é gerado pelo emissor."}),`
`,a.jsx(e.p,{children:a.jsx(e.strong,{children:"O que acontece quando minha transação não é confirmada?"})}),`
`,a.jsx(e.p,{children:"O valor bloqueado no cartão fica pendente por um tempo (tipicamente 7 a 30 dias). Se o emissor não recebe confirmação nem mensagem de desfazimento, eventualmente libera o valor. O estabelecimento não recebe pela venda."}),`
`,a.jsx(e.p,{children:a.jsx(e.strong,{children:"Chargeback faz parte do ciclo de vida?"})}),`
`,a.jsx(e.p,{children:"Chargeback é um evento excepcional dentro do ciclo. Pode acontecer até 120 dias depois da transação, se o usuário contesta junto ao emissor. Se o chargeback é perdido, o estabelecimento fica sem o valor."}),`
`,a.jsx(e.p,{children:a.jsx(e.strong,{children:"O que é arquivo de conciliação transacional?"})}),`
`,a.jsx(e.p,{children:"É o arquivo enviado ao final de cada dia com todas as transações capturadas pelo meio de captura. Serve como fonte da verdade para liquidação financeira e para reconciliar autorizações com capturas efetivas."}),`
`,a.jsx(e.p,{children:a.jsx(e.strong,{children:"Como o ciclo é diferente em arranjo fechado?"})}),`
`,a.jsxs(e.p,{children:["Em ",a.jsx(e.a,{href:"/conteudos/arranjo-aberto-vs-arranjo-fechado",children:"arranjo fechado"}),", toda a cadeia (emissor, captura, processamento) está sob a mesma operação. O ciclo tem as mesmas etapas, mas com menos atores. Mensagens podem ser internalizadas sem passar por bandeira ou adquirente externo."]}),`
`,a.jsx(e.p,{children:a.jsx(e.strong,{children:"Onde posso aprender mais sobre o ciclo?"})}),`
`,a.jsxs(e.p,{children:["O padrão ",a.jsx(e.a,{href:"/conteudos/iso-8583-protocolo-cartoes",children:"ISO 8583"})," define formalmente os tipos de mensagem e os fluxos. As bandeiras publicam documentação técnica para emissores homologados. BaaS e processadoras também têm documentação detalhada do ciclo para seus clientes."]}),`
`,a.jsx(e.h2,{id:"próximo-passo",children:a.jsx(e.a,{href:"#próximo-passo",children:"Próximo passo"})}),`
`,a.jsxs(e.p,{children:["Se você está montando operação de cartão e precisa garantir que o ciclo de vida das transações está bem implementado, a JUST ajuda a desenhar os fluxos e monitorar métricas críticas. ",a.jsx(e.a,{href:"/contato",children:"Fale com a gente"}),"."]})]})}function oe(o={}){const{wrapper:e}=o.components||{};return e?a.jsx(e,{...o,children:a.jsx(q,{...o})}):q(o)}const re=Object.freeze(Object.defineProperty({__proto__:null,default:oe},Symbol.toStringTag,{value:"Module"}));function S(o){const e={a:"a",h1:"h1",h2:"h2",h3:"h3",p:"p",strong:"strong",table:"table",tbody:"tbody",td:"td",th:"th",thead:"thead",tr:"tr",...o.components};return a.jsxs(a.Fragment,{children:[a.jsx(e.h1,{id:"como-solicitar-um-biniin-no-brasil-o-passo-a-passo-da-abnt",children:a.jsx(e.a,{href:"#como-solicitar-um-biniin-no-brasil-o-passo-a-passo-da-abnt",children:"Como solicitar um BIN/IIN no Brasil: o passo a passo da ABNT"})}),`
`,a.jsx(e.h2,{id:"resposta-direta",children:a.jsx(e.a,{href:"#resposta-direta",children:"Resposta direta"})}),`
`,a.jsx(e.p,{children:"No Brasil, o registro de BIN (Bank Identification Number) e IIN (Issuer Identification Number) é controlado pela ABNT, que atua como Registration Authority do padrão ISO/IEC 7812-1. O processo envolve enviar e-mail à ABNT, preencher o formulário oficial (em inglês, no padrão internacional) e aguardar aprovação. Custa entre R$ 3.000 e R$ 5.000, leva em torno de 30 dias e resulta em um identificador único de 6 ou 8 dígitos que sua empresa pode usar para emitir cartões próprios, com bandeira própria ou homologados em bandeiras abertas."}),`
`,a.jsx(e.h2,{id:"o-que-é-bin-e-o-que-é-iin",children:a.jsx(e.a,{href:"#o-que-é-bin-e-o-que-é-iin",children:"O que é BIN e o que é IIN"})}),`
`,a.jsx(e.p,{children:"Os dois termos se confundem e muita gente usa como sinônimos. Tecnicamente têm origens diferentes."}),`
`,a.jsxs(e.p,{children:[a.jsx(e.strong,{children:"BIN (Bank Identification Number)"})," é o termo histórico. Surgiu quando praticamente só bancos emitiam cartões. São os primeiros 6 dígitos do número impresso no cartão, que identificam quem emitiu aquele plástico."]}),`
`,a.jsxs(e.p,{children:[a.jsx(e.strong,{children:"IIN (Issuer Identification Number)"}),' é o termo moderno e oficial da norma ISO/IEC 7812-1. Com a expansão da emissão para fintechs, companhias de benefícios e varejistas, "Bank" ficou ultrapassado. Hoje o IIN é o termo tecnicamente correto, e a norma está em transição de 6 para 8 dígitos.']}),`
`,a.jsx(e.p,{children:"Na prática, no Brasil e no mundo, se usa BIN e IIN como sinônimos. Esse artigo segue essa convenção."}),`
`,a.jsx(e.p,{children:"Os dígitos do IIN identificam o emissor do cartão no sistema global de pagamentos. Sem IIN registrado, o roteamento de transações não consegue encontrar quem emitiu o cartão. É o equivalente a um domínio no DNS: sem ele, ninguém sabe pra onde mandar o pacote."}),`
`,a.jsx(e.h2,{id:"quando-você-precisa-de-bin-próprio",children:a.jsx(e.a,{href:"#quando-você-precisa-de-bin-próprio",children:"Quando você precisa de BIN próprio"})}),`
`,a.jsx(e.p,{children:"Nem toda operação de cartão precisa de BIN próprio. A regra geral:"}),`
`,a.jsxs(e.p,{children:["Se você opera via ",a.jsx(e.a,{href:"/conteudos/bin-sponsor-o-que-e",children:"BIN Sponsor"})," em bandeira aberta (Visa, Mastercard, Elo, Amex), não precisa. Você usa o BIN do sponsor."]}),`
`,a.jsxs(e.p,{children:["Se você emite cartão private label em ",a.jsx(e.a,{href:"/conteudos/arranjo-aberto-vs-arranjo-fechado",children:"arranjo fechado"})," em rede própria, precisa. O BIN próprio identifica seus cartões no seu próprio ecossistema."]}),`
`,a.jsx(e.p,{children:"Se você quer se tornar emissor direto de uma bandeira aberta, precisa. A bandeira exige BIN próprio para homologar sua operação."}),`
`,a.jsx(e.p,{children:"Se você tem um arranjo de pagamento próprio que interopera com outros, precisa. O IIN é o que permite roteamento entre sistemas."}),`
`,a.jsx(e.p,{children:"Na maioria das operações de fintech que começam hoje, o caminho é via sponsor. Mas operações maduras, private labels e esquemas proprietários dependem de BIN registrado."}),`
`,a.jsx(e.h2,{id:"a-abnt-como-autoridade-de-registro",children:a.jsx(e.a,{href:"#a-abnt-como-autoridade-de-registro",children:"A ABNT como autoridade de registro"})}),`
`,a.jsx(e.p,{children:"No mundo, a ISO/IEC 7812-1 delega o controle dos registros para Registration Authorities nacionais. Nos Estados Unidos, é a American Bankers Association (ABA). No Brasil, é a Associação Brasileira de Normas Técnicas (ABNT)."}),`
`,a.jsx(e.p,{children:"A ABNT tem um papel administrativo no processo. Recebe o pedido, valida o candidato, atribui um identificador único e comunica a aprovação ao sistema internacional. Não faz supervisão regulatória. Não analisa modelo de negócio. Não precisa aprovação do BACEN como pré-requisito (embora o BACEN tenha que autorizar a operação como um todo quando o caso exige)."}),`
`,a.jsx(e.p,{children:"Quem registra BIN junto à ABNT recebe um número único que ninguém mais no mundo vai poder usar. É uma atribuição global, administrada localmente."}),`
`,a.jsx(e.h2,{id:"o-passo-a-passo-do-processo",children:a.jsx(e.a,{href:"#o-passo-a-passo-do-processo",children:"O passo a passo do processo"})}),`
`,a.jsx(e.p,{children:"Depois de várias operações que acompanhei, o fluxo prático é esse:"}),`
`,a.jsx(e.h3,{id:"passo-1-contato-inicial-com-a-abnt",children:a.jsx(e.a,{href:"#passo-1-contato-inicial-com-a-abnt",children:"Passo 1: Contato inicial com a ABNT"})}),`
