`,a.jsx(e.p,{children:"Para operações em arranjo fechado com foco em grandes redes, conciliação facilmente consome R$ 100 mil a R$ 300 mil entre setup e primeiro ano. Não é item marginal."}),`
`,a.jsx(e.h2,{id:"erros-comuns",children:a.jsx(e.a,{href:"#erros-comuns",children:"Erros comuns"})}),`
`,a.jsxs(e.p,{children:[a.jsx(e.strong,{children:"Adiar homologação até que o grande varejista peça."})," Quando o varejista pede, já é tarde. A homologação leva meses e trava a negociação comercial. O certo é se homologar antes, como capability para vender."]}),`
`,a.jsxs(e.p,{children:[a.jsx(e.strong,{children:"Homologar sem volume para sustentar."})," Alguns emissores se homologam e depois percebem que não têm volume suficiente para cobrir o custo anual. Homologue em plataforma quando já tem ou está a caminho de ter clientes que usam aquela plataforma."]}),`
`,a.jsxs(e.p,{children:[a.jsx(e.strong,{children:"Ignorar ajustes pós-liquidação."})," Conciliação não termina no arquivo diário. Ajustes (chargebacks, estornos tardios) aparecem dias ou semanas depois. Processo de conciliação precisa prever reconciliação contínua, não pontual."]}),`
`,a.jsxs(e.p,{children:[a.jsx(e.strong,{children:"Não monitorar divergências."}),' Muitas operações geram arquivo, enviam à plataforma e acreditam que "deu certo". Monitoramento ativo de divergências entre autorizado, capturado, liquidado é o que transforma conciliação em valor real.']}),`
`,a.jsx(e.h2,{id:"faq",children:a.jsx(e.a,{href:"#faq",children:"FAQ"})}),`
`,a.jsx(e.p,{children:a.jsx(e.strong,{children:"O que é conciliação financeira em cartão?"})}),`
`,a.jsx(e.p,{children:"É o processo em que um estabelecimento comercial compara as transações de cartão que realizou com os valores que efetivamente recebeu, depois de tarifas e ajustes. Serve para detectar erros, fraudes e discrepâncias no fluxo financeiro."}),`
`,a.jsx(e.p,{children:a.jsx(e.strong,{children:"Quais são as principais plataformas de conciliação no Brasil?"})}),`
`,a.jsx(e.p,{children:"Conciliadora (Grupo Boticário), Equals, Grupo Nexera e BoaVista são as quatro com maior penetração. Existem também plataformas menores especializadas em nichos específicos."}),`
`,a.jsx(e.p,{children:a.jsx(e.strong,{children:"Quanto custa homologar em uma plataforma de conciliação?"})}),`
`,a.jsx(e.p,{children:"Entre R$ 5.000 e R$ 50.000 por plataforma, mais manutenção anual de R$ 5.000 a R$ 30.000. Homologar em 4 plataformas para cobrir grandes redes pode custar R$ 40.000 a R$ 200.000."}),`
`,a.jsx(e.p,{children:a.jsx(e.strong,{children:"Quanto tempo leva para homologar?"})}),`
`,a.jsx(e.p,{children:"Entre 30 e 120 dias, dependendo da plataforma e da complexidade. Inclui desenvolvimento do parser específico, testes com volume real e publicação."}),`
`,a.jsx(e.p,{children:a.jsx(e.strong,{children:"Preciso me homologar em alguma plataforma se não vendo para grandes varejistas?"})}),`
`,a.jsx(e.p,{children:"Não necessariamente. Para pequenos estabelecimentos, conciliação costuma ser feita pelo portal do próprio emissor. Plataformas profissionais viram necessidade a partir de um porte em que o estabelecimento tem volume que justifica o custo de ferramenta externa."}),`
`,a.jsx(e.p,{children:a.jsx(e.strong,{children:"Conciliação é obrigatória regulatoriamente?"})}),`
`,a.jsx(e.p,{children:"Não há obrigação regulatória específica de usar plataforma externa. A obrigação é contábil: toda empresa precisa conciliar o que recebe. Como conciliar fica a critério da empresa. Plataformas automatizam essa obrigação."}),`
`,a.jsx(e.p,{children:a.jsx(e.strong,{children:"Arquivo de conciliação é o mesmo arquivo de liquidação?"})}),`
`,a.jsx(e.p,{children:"Não exatamente. Arquivo de conciliação pode trazer dados da transação (dia seguinte à compra) e da liquidação (dia seguinte ao pagamento). Em algumas operações, os dois são unificados; em outras, são separados."}),`
`,a.jsx(e.p,{children:a.jsx(e.strong,{children:"Posso usar só integração por API sem arquivo?"})}),`
`,a.jsx(e.p,{children:"Sim, se a plataforma suportar. Cada vez mais plataformas aceitam integração por API. Em 2026, ainda é comum ter os dois métodos, mas a migração para API está acontecendo."}),`
`,a.jsx(e.p,{children:a.jsx(e.strong,{children:"Hub de conciliação vale a pena?"})}),`
`,a.jsx(e.p,{children:"Se você vai cobrir 3 ou mais plataformas, sim. Um hub centraliza o esforço de homologação inicial e manutenção. Se cobre só 1-2 plataformas, homologação direta tende a ser mais econômica."}),`
`,a.jsx(e.p,{children:a.jsx(e.strong,{children:"Quem paga pela homologação: o emissor ou o estabelecimento?"})}),`
`,a.jsx(e.p,{children:"Tipicamente o emissor. É custo de estrutura para que ele possa ser aceito em estabelecimentos que usam aquela plataforma. O estabelecimento geralmente paga à plataforma uma mensalidade separada pelo serviço de conciliação que recebe."}),`
`,a.jsx(e.h2,{id:"próximo-passo",children:a.jsx(e.a,{href:"#próximo-passo",children:"Próximo passo"})}),`
`,a.jsxs(e.p,{children:["Se você está estruturando operação de cartão em arranjo fechado e precisa montar a conciliação para atender grandes varejistas, a JUST oferece hub de conciliação que centraliza homologações em múltiplas plataformas. ",a.jsx(e.a,{href:"/contato",children:"Fale com a gente"})," para entender como funciona."]})]})}function ne(o={}){const{wrapper:e}=o.components||{};return e?a.jsx(e,{...o,children:a.jsx(P,{...o})}):P(o)}const de=Object.freeze(Object.defineProperty({__proto__:null,default:ne},Symbol.toStringTag,{value:"Module"}));function A(o){const e={a:"a",h2:"h2",p:"p",strong:"strong",table:"table",tbody:"tbody",td:"td",th:"th",thead:"thead",tr:"tr",...o.components};return a.jsxs(a.Fragment,{children:[a.jsx(e.h2,{id:"resposta-direta",children:a.jsx(e.a,{href:"#resposta-direta",children:"Resposta direta"})}),`
`,a.jsx(e.p,{children:"Na prática brasileira, os termos cartão empresarial e cartão corporativo são usados como sinônimos. A diferença real está em quem responde pela dívida (PJ + sócios vs PJ exclusivamente), no nível de controle de gasto e na contabilização."}),`
`,a.jsx(e.p,{children:'Quem escreve sobre o assunto gosta de criar distinções que o mercado não usa. A verdade é que você vai ouvir "cartão empresarial" num banco, "cartão corporativo" em outro, e os dois vão oferecer produtos tecnicamente equivalentes.'}),`
`,a.jsx(e.p,{children:"O que vale a pena entender são as diferenças que aparecem no contrato, não no nome do produto."}),`
`,a.jsx(e.h2,{id:"a-confusão-dos-termos",children:a.jsx(e.a,{href:"#a-confusão-dos-termos",children:"A confusão dos termos"})}),`
`,a.jsx(e.p,{children:'Se você pesquisar "cartão empresarial" e "cartão corporativo" no Google, vai encontrar artigos jurando que um é para PME e outro é para grande empresa. Outros vão dizer que empresarial tem responsabilidade solidária e corporativo não. Outros vão inverter.'}),`
`,a.jsx(e.p,{children:'Nenhuma dessas definições é consagrada em lei, regulação do BACEN ou manual de bandeira. A Lei 12.865/2013 fala em "cartão de pagamento" sem distinguir empresarial de corporativo. A Resolução BCB 150/2021 idem.'}),`
`,a.jsx(e.p,{children:'Na prática, cada emissor nomeia seu produto como quer. O Itaú tem "Empresarial" e "Corporate". O Bradesco tem "Empresarial" e "Corporativo". Fintechs recentes tendem a usar "corporativo" porque soa mais sofisticado, mas operam lógica PME.'}),`
`,a.jsx(e.p,{children:"O que diferencia produtos de cartão PJ não é o nome. São as cláusulas."}),`
`,a.jsx(e.h2,{id:"o-que-muda-de-verdade-entre-os-produtos-pj",children:a.jsx(e.a,{href:"#o-que-muda-de-verdade-entre-os-produtos-pj",children:"O que muda de verdade entre os produtos PJ"})}),`
`,a.jsx(e.p,{children:"Esqueça o rótulo. Compare essas sete dimensões quando estiver avaliando um cartão PJ."}),`
