`,a.jsx(e.h2,{id:"como-a-just-ajuda-nessa-conta",children:a.jsx(e.a,{href:"#como-a-just-ajuda-nessa-conta",children:"Como a JUST ajuda nessa conta"})}),`
`,a.jsx(e.p,{children:"Se você chegou até aqui e está montando a projeção da sua operação de cartão, o próximo passo é botar os números reais na mesa. A JUST trabalha com fintechs e empresas que querem estruturar operação de cartão e ajuda a desenhar o P&L, escolher o programa certo, negociar com BaaS, e montar o plano de break-even."}),`
`,a.jsxs(e.p,{children:["Em breve, vamos lançar uma calculadora pública que permite simular o cenário da sua operação em poucos cliques. Por enquanto, se você quer fazer essa conta com mais precisão, ",a.jsx(e.a,{href:"/contato",children:"fale com a gente"})," e a gente monta junto."]}),`
`,a.jsx(e.h2,{id:"faq",children:a.jsx(e.a,{href:"#faq",children:"FAQ"})}),`
`,a.jsx(e.p,{children:a.jsx(e.strong,{children:"Quanto custa para começar a emitir cartão no Brasil?"})}),`
`,a.jsx(e.p,{children:"Via BIN Sponsor (modelo mais comum), o CAPEX inicial fica entre R$ 250.000 e R$ 1.400.000 dependendo da complexidade. Via licença própria, entre R$ 5 milhões e R$ 15 milhões."}),`
`,a.jsx(e.p,{children:a.jsx(e.strong,{children:"Qual é o fee mínimo mensal de um BaaS?"})}),`
`,a.jsx(e.p,{children:"Varia de R$ 10.000 a R$ 50.000 no mercado brasileiro. Pode ser menor em operações de nicho, maior em operações com programas customizados ou volume garantido."}),`
`,a.jsx(e.p,{children:a.jsx(e.strong,{children:"Quantos cartões preciso para chegar ao break-even?"})}),`
`,a.jsx(e.p,{children:"Depende do modelo. Para cartão de crédito consumidor via BaaS, entre 30 mil e 80 mil ativos. Para pré-pago corporativo, entre 5 mil e 15 mil. Para private label em arranjo fechado, entre 3 mil e 10 mil."}),`
`,a.jsx(e.p,{children:a.jsx(e.strong,{children:"Quanto tempo até o break-even?"})}),`
`,a.jsx(e.p,{children:"Entre 12 e 24 meses para a maioria das operações bem planejadas. Mais rápido para private label ou B2B com alto ticket. Mais lento para operações de crédito consumidor com licença própria."}),`
`,a.jsx(e.p,{children:a.jsx(e.strong,{children:"Quanto custa produzir um cartão físico?"})}),`
`,a.jsx(e.p,{children:"Plástico padrão com embolsamento e envio: R$ 10 a R$ 25. Plástico premium (metal ou design especial): R$ 30 a R$ 100. Considere reposição de 0,5 cartão por usuário por ano."}),`
`,a.jsx(e.p,{children:a.jsx(e.strong,{children:"Qual o custo mensal por usuário ativo?"})}),`
`,a.jsx(e.p,{children:"Entre R$ 2,50 e R$ 16 em custos variáveis, dependendo da frequência de uso, se usa Apple Pay, e do volume transacionado."}),`
`,a.jsx(e.p,{children:a.jsx(e.strong,{children:"Posso começar sem cartão físico?"})}),`
`,a.jsx(e.p,{children:"Sim. Cartão virtual e cartão tokenizado (para Apple Pay, Google Pay) já dão boa experiência em boa parte dos casos de uso. Muitas operações começam só com virtual e oferecem físico como premium ou opt-in."}),`
`,a.jsx(e.p,{children:a.jsx(e.strong,{children:"Qual é o custo de não usar BaaS e ter licença própria?"})}),`
`,a.jsx(e.p,{children:"Setup inicial entre R$ 5 milhões e R$ 15 milhões, time de 30+ pessoas, prazo de go-live de 12 a 24 meses, e obrigações regulatórias diretas do BACEN. Só faz sentido com operação validada e volume garantido."}),`
`,a.jsx(e.p,{children:a.jsx(e.strong,{children:"O setup com BaaS é negociável?"})}),`
`,a.jsx(e.p,{children:"Sim. Todos os itens (setup, fee mínimo, take rate, tarifas unitárias) são negociáveis. Seu poder de barganha depende de volume projetado, exclusividade, tempo de contrato e prontidão técnica."}),`
`,a.jsx(e.p,{children:a.jsx(e.strong,{children:"Como estimar quanto a minha operação vai custar antes de fechar contrato?"})}),`
`,a.jsx(e.p,{children:"Use as faixas desse guia como referência, converse com dois ou três BaaS diferentes para benchmark de preço, e monte uma planilha com CAPEX, custos fixos, variáveis, produção de plástico e projeção de receita. A conta só fecha quando você projeta 12 a 24 meses à frente."}),`
`,a.jsx(e.h2,{id:"próximo-passo",children:a.jsx(e.a,{href:"#próximo-passo",children:"Próximo passo"})}),`
`,a.jsxs(e.p,{children:["Se você está modelando uma operação de cartão e precisa de ajuda para desenhar o P&L completo, calcular o break-even e escolher o caminho certo (arranjo aberto, private label, licença própria), a JUST estrutura esse trabalho com você. ",a.jsx(e.a,{href:"/contato",children:"Fale com a gente"}),"."]})]})}function be(o={}){const{wrapper:e}=o.components||{};return e?a.jsx(e,{...o,children:a.jsx(E,{...o})}):E(o)}const fe=Object.freeze(Object.defineProperty({__proto__:null,default:be},Symbol.toStringTag,{value:"Module"}));function R(o){const e={a:"a",h1:"h1",h2:"h2",p:"p",strong:"strong",...o.components};return a.jsxs(a.Fragment,{children:[a.jsx(e.h1,{id:"receita-de-float-em-emissão-de-cartões-o-dinheiro-parado-que-rende-enquanto-espera",children:a.jsx(e.a,{href:"#receita-de-float-em-emissão-de-cartões-o-dinheiro-parado-que-rende-enquanto-espera",children:"Receita de float em emissão de cartões: o dinheiro parado que rende enquanto espera"})}),`
`,a.jsx(e.h2,{id:"resposta-direta",children:a.jsx(e.a,{href:"#resposta-direta",children:"Resposta direta"})}),`
`,a.jsx(e.p,{children:"Receita de float é o rendimento financeiro que uma instituição de pagamento gera ao investir, em títulos públicos seguros, o dinheiro que fica parado nas contas enquanto espera ser liquidado para o estabelecimento comercial. Em operações de cartão de crédito com liquidação em 28 dias (D+28), o float pode chegar a 1% a 1,5% do TPV mensal a títulos da Selic. É receita legítima do emissor e deve ser repassada pelo BaaS ao cliente que contratou o BIN Sponsor."}),`
`,a.jsx(e.h2,{id:"o-que-é-float-na-prática",children:a.jsx(e.a,{href:"#o-que-é-float-na-prática",children:"O que é float, na prática"})}),`
`,a.jsx(e.p,{children:"Quando você paga uma compra de R$ 100 no cartão de crédito, o estabelecimento não recebe os R$ 100 no dia seguinte. Recebe geralmente em 28 dias corridos (D+28), no modelo padrão de cartão de crédito à vista no Brasil. Esse prazo existe porque a bandeira, o adquirente, a instituição de pagamento e o sistema como um todo trabalham com janelas de liquidação padronizadas."}),`
`,a.jsx(e.p,{children:"Durante esses 28 dias, o dinheiro sai da conta do consumidor (ou da fatura dele, no caso de crédito), passa pela bandeira, passa pelo adquirente, passa pela instituição de pagamento do emissor, e em algum momento aterriza na conta do estabelecimento."}),`
`,a.jsx(e.p,{children:"Enquanto o dinheiro está parado em algum ponto desse fluxo, ele não está rendendo para o dono final. Está rendendo para quem o tem em custódia naquele instante. É isso que a gente chama de float."}),`
`,a.jsx(e.p,{children:"No Brasil, onde a Selic anual hoje está perto de 10% ao ano, o dinheiro em custódia rende de forma consistente em títulos públicos de curto prazo (Tesouro Selic, DI, operações compromissadas). Quem tem R$ 100 milhões em float ganha R$ 800 mil a R$ 900 mil por mês, só por ter o dinheiro passando pela conta. É receita de verdade."}),`
`,a.jsx(e.h2,{id:"por-que-o-float-existe",children:a.jsx(e.a,{href:"#por-que-o-float-existe",children:"Por que o float existe"})}),`
`,a.jsx(e.p,{children:"O float nasce da assimetria entre a janela de pagamento do consumidor e a janela de recebimento do estabelecimento. Em cartão de crédito, essa assimetria é grande:"}),`
`,a.jsx(e.p,{children:"O consumidor paga a fatura em datas fixas (normalmente mensal), mas a transação aconteceu em qualquer dia do ciclo."}),`
`,a.jsx(e.p,{children:"O estabelecimento quer receber o quanto antes, mas a janela padrão é D+28."}),`
`,a.jsx(e.p,{children:"A adquirente antecipa o pagamento ao estabelecimento (via recebível), cobrando uma taxa que compensa o risco. Essa antecipação é o que sustenta o modelo comercial de Stone, Cielo e Rede hoje. Mesmo assim, a liquidação formal da transação segue o calendário da bandeira."}),`
`,a.jsx(e.p,{children:"No meio desse fluxo, o dinheiro aterrissa temporariamente em contas de instituições de pagamento. Cada parada gera um float. Quem tem a conta em custódia nessa parada rende o dinheiro ali."}),`
`,a.jsx(e.p,{children:"Em cartão pré-pago e débito, o prazo de liquidação é D+2 (dois dias úteis). O float existe, mas é muito menor. Em cartão de crédito, D+28, o float é relevante."}),`
`,a.jsx(e.h2,{id:"quanto-rende-a-matemática",children:a.jsx(e.a,{href:"#quanto-rende-a-matemática",children:"Quanto rende: a matemática"})}),`
`,a.jsx(e.p,{children:"Vamos fazer a conta com números realistas. Imagine uma fintech que emite cartões de crédito, tem 30 mil cartões ativos, ticket médio mensal por usuário de R$ 1.500. Resulta em TPV mensal de R$ 45 milhões."}),`
`,a.jsx(e.p,{children:"O prazo médio de liquidação é D+28. Isso significa que, a qualquer momento, há aproximadamente 28 dias de TPV parado em diferentes pontos do fluxo. Considerando a conta da instituição de pagamento que sustenta o emissor, o saldo médio parado pode ser de 15 a 25 dias de TPV, dependendo da estrutura contratual."}),`
`,a.jsx(e.p,{children:"Usando 20 dias como média:"}),`
`,a.jsx(e.p,{children:"R$ 45 milhões mensais = R$ 1,5 milhão de TPV diário."}),`
`,a.jsx(e.p,{children:"R$ 1,5 milhão × 20 dias = R$ 30 milhões em saldo médio parado na conta da instituição de pagamento."}),`
`,a.jsx(e.p,{children:"Com Selic a 10% ao ano (aproximadamente 0,8% ao mês), o rendimento desses R$ 30 milhões é de R$ 240 mil por mês. Isso é só rendimento financeiro. Sem nenhuma atividade comercial adicional."}),`
`,a.jsx(e.p,{children:"Em base anual, são R$ 2,88 milhões de receita de float para essa operação. Dependendo do contrato com o BaaS, essa receita é repassada em 50% a 100% para a fintech."}),`
`,a.jsx(e.p,{children:"Para uma operação de 30 mil cartões, isso muda o P&L de forma material. Em cartão de crédito com liquidação longa, o float é a segunda fonte de receita mais importante, logo depois do intercâmbio."}),`
`,a.jsx(e.h2,{id:"quem-é-dono-do-float",children:a.jsx(e.a,{href:"#quem-é-dono-do-float",children:"Quem é dono do float"})}),`
`,a.jsx(e.p,{children:"Aqui é onde a conversa contratual fica crítica."}),`
`,a.jsx(e.p,{children:"Juridicamente, o float é gerado na conta da instituição de pagamento que está com o dinheiro em custódia. Regulatoriamente, essa instituição pode investir o float em títulos públicos seguros, respeitando as exigências do BACEN sobre reservas e liquidez."}),`
`,a.jsx(e.p,{children:"Comercialmente, o float é considerado receita do emissor. Quem assumiu o risco de emitir o cartão, quem bancou a relação com o cliente, quem bancou os custos operacionais, esse é quem tem direito à receita gerada pelo dinheiro que passa pelo cartão dele."}),`
`,a.jsxs(e.p,{children:["Na prática, em uma operação via ",a.jsx(e.a,{href:"/conteudos/bin-sponsor-o-que-e",children:"BIN Sponsor"}),", o float é gerado na conta do BaaS (sponsor). O BaaS então repassa o float ao cliente que contratou o BIN, via contrato."]}),`
`,a.jsx(e.p,{children:"O problema é que muita fintech nem sabe que tem direito a esse repasse. Assina contrato com o BaaS, foca no intercâmbio, e deixa de pegar a receita de float na mesa. Em operações de crédito relevantes, são centenas de milhares de reais por ano ficando no BaaS em vez de ir para a fintech."}),`
`,a.jsx(e.p,{children:"Se você contratou BaaS e não tem cláusula clara de repasse de float, levanta a mão, chama seu account e pergunta. Isso é dinheiro seu."}),`
`,a.jsx(e.h2,{id:"como-o-float-é-repassado",children:a.jsx(e.a,{href:"#como-o-float-é-repassado",children:"Como o float é repassado"})}),`
`,a.jsx(e.p,{children:"Os modelos comerciais mais comuns no mercado:"}),`
`,a.jsxs(e.p,{children:[a.jsx(e.strong,{children:"Repasse integral (100% do float)."})," O BaaS repassa ao emissor 100% do rendimento financeiro gerado em cima do saldo em custódia. Geralmente, o BaaS cobra uma tarifa de administração em troca, ou uma taxa unitária já embutida nas outras tarifas. É o modelo mais transparente."]}),`
`,a.jsxs(e.p,{children:[a.jsx(e.strong,{children:"Repasse parcial (50% a 80% do float)."})," O BaaS retém uma parcela (20% a 50%) como remuneração pelo serviço de gestão do float. Em troca, pode oferecer tarifas unitárias menores nos outros serviços."]}),`
`,a.jsxs(e.p,{children:[a.jsx(e.strong,{children:"Sem repasse de float (0%)."})," Alguns contratos (em geral mais antigos ou com BaaS menos transparentes) não têm cláusula de repasse. Todo o float fica com o BaaS. Se você está em um contrato assim, renegocie."]}),`
`,a.jsx(e.p,{children:"A frequência do repasse é geralmente mensal. O cálculo é feito com base no saldo médio diário da conta, aplicando a rentabilidade líquida dos investimentos que o BaaS fez no período. O BaaS deve dar visibilidade do cálculo mensal."}),`
`,a.jsx(e.h2,{id:"quando-o-float-importa-mais",children:a.jsx(e.a,{href:"#quando-o-float-importa-mais",children:"Quando o float importa mais"})}),`
`,a.jsx(e.p,{children:"O float é material em cenários específicos:"}),`
`,a.jsxs(e.p,{children:[a.jsx(e.strong,{children:"Cartão de crédito com D+28."})," Já cobrimos acima. É o cenário clássico de float relevante. Quanto maior o ticket médio e a frequência de uso, maior o saldo parado e maior o float."]}),`
`,a.jsxs(e.p,{children:[a.jsx(e.strong,{children:"Operações com saldo mantido em conta."})," Algumas operações (contas digitais, wallets corporativas, cartões com saldo pré-carregado) mantêm valores parados em conta por tempos variáveis. Esse saldo também gera float."]}),`
`,a.jsxs(e.p,{children:[a.jsx(e.strong,{children:"Voucher e benefícios corporativos com carregamento mensal."})," O empregador deposita R$ 800 por funcionário no início do mês. Parte desse saldo é gasta ao longo do mês, mas sempre há um saldo residual. Em uma base de 100 mil funcionários, isso é um estoque permanente de dezenas de milhões de reais em float."]}),`
`,a.jsxs(e.p,{children:[a.jsx(e.strong,{children:"Antecipação de recebíveis integrada."})," Quando a fintech também atua como adquirente ou sub-adquirente, o float se soma ao spread da antecipação. Os dois se potencializam. É o modelo que alimenta Stone e Cielo no lado da adquirência."]}),`
`,a.jsx(e.h2,{id:"quando-o-float-não-importa",children:a.jsx(e.a,{href:"#quando-o-float-não-importa",children:"Quando o float não importa"})}),`
`,a.jsx(e.p,{children:"Em cartões pré-pago sem saldo mantido e em operações de débito puro (D+2), o float é quase irrelevante. Você vai ter rendimento de 0,05% a 0,1% do TPV mensal. Em uma operação pequena, isso pode ser menos de R$ 10 mil ao mês. Não move ponteiro."}),`
`,a.jsx(e.p,{children:"Em operações com baixa recorrência e baixo ticket, o float também perde peso. Se o usuário usa o cartão uma vez por mês com ticket de R$ 100, o saldo parado médio é pequeno e o float gerado é irrisório."}),`
`,a.jsx(e.p,{children:"Por isso a gente na JUST insiste com clientes que estão em arranjo aberto: olhar o float como função direta de duas variáveis, prazo de liquidação e TPV. Se você tem crédito e escala, o float é receita relevante. Se você tem débito e operação pequena, o float é rodapé."}),`
`,a.jsx(e.h2,{id:"como-negociar-repasse-de-float-com-o-baas",children:a.jsx(e.a,{href:"#como-negociar-repasse-de-float-com-o-baas",children:"Como negociar repasse de float com o BaaS"})}),`
`,a.jsx(e.p,{children:"Três pontos práticos para ter em mão antes da conversa:"}),`
`,a.jsx(e.p,{children:"Primeiro, calcule quanto de float sua operação está gerando. Use a fórmula: TPV mensal × (prazo médio de liquidação / 30) × Selic mensal. Traga o número para a mesa. BaaS não vai ajudar se você não souber quanto está na mesa."}),`
`,a.jsx(e.p,{children:"Segundo, peça detalhamento da cláusula atual. Se o contrato não cita float explicitamente, presuma que o BaaS está embolsando 100% até prova em contrário. Abra a pauta."}),`
`,a.jsx(e.p,{children:"Terceiro, negocie antes de migrar em volume. Em operação pequena, seu poder de barganha é baixo. Conforme você cresce, o BaaS tem incentivo a manter você em vez de perder para concorrência. O momento de renegociar cláusula de float é quando você tem 20 mil, 50 mil, 100 mil cartões ativos. Antes disso, foque no produto."}),`
`,a.jsx(e.h2,{id:"impactos-fiscais",children:a.jsx(e.a,{href:"#impactos-fiscais",children:"Impactos fiscais"})}),`
`,a.jsx(e.p,{children:"Ponto importante e pouco falado: float é receita financeira, não operacional. Isso muda o tratamento tributário."}),`
`,a.jsx(e.p,{children:"No Brasil, receita financeira é tributada pelo IRPJ e CSLL conforme o regime da empresa (lucro real ou presumido). PIS e COFINS incidem em alíquotas diferentes de receita de serviços. Em lucro real, receita financeira é tributada a 0,65% de PIS e 4% de COFINS, enquanto receita de serviços é 1,65% de PIS e 7,6% de COFINS. Em lucro presumido, a alíquota é similar a PJ com PIS/COFINS cumulativos."}),`
`,a.jsx(e.p,{children:"O BaaS pode repassar o float já líquido dos impostos dele (retidos na fonte) ou bruto, e você paga os impostos na sua ponta. Dependendo da estrutura, muda quanto entra efetivamente no caixa. Alinhe com seu contador antes de assinar."}),`
`,a.jsx(e.h2,{id:"faq",children:a.jsx(e.a,{href:"#faq",children:"FAQ"})}),`
`,a.jsx(e.p,{children:a.jsx(e.strong,{children:"O que é receita de float em cartão?"})}),`
`,a.jsx(e.p,{children:"É o rendimento financeiro gerado quando dinheiro de transações de cartão fica parado em conta aguardando liquidação. A instituição de pagamento investe esse saldo em títulos públicos e o rendimento é receita do emissor (repassada pelo BaaS, se o modelo for BIN Sponsor)."}),`
`,a.jsx(e.p,{children:a.jsx(e.strong,{children:"Quanto rende o float de uma operação de cartão?"})}),`
`,a.jsx(e.p,{children:"Em cartão de crédito com D+28, o float rende aproximadamente 1% a 1,5% do TPV mensal a títulos da Selic atual (10% ao ano). Em débito e pré-pago, o float é muito menor, perto de 0,05% a 0,1% do TPV."}),`
`,a.jsx(e.p,{children:a.jsx(e.strong,{children:"Quem recebe o float: o emissor ou o BaaS?"})}),`
`,a.jsx(e.p,{children:"Comercialmente, o float é receita do emissor (a fintech que contratou o BIN Sponsor). O BaaS gerencia o dinheiro e repassa a receita via contrato. Se sua operação está via BaaS, confira se o contrato tem cláusula clara de repasse de float."}),`
`,a.jsx(e.p,{children:a.jsx(e.strong,{children:"Float rende Selic?"})}),`
`,a.jsx(e.p,{children:"Rende aproximadamente Selic líquida (descontando taxa de administração dos investimentos e impostos na fonte, se houver). O BaaS investe o saldo em títulos públicos de curto prazo (Tesouro Selic, DI, compromissadas) que seguem de perto a Selic."}),`
`,a.jsx(e.p,{children:a.jsx(e.strong,{children:"Por que o prazo de liquidação é D+28?"})}),`
`,a.jsx(e.p,{children:"D+28 é o padrão para cartão de crédito à vista no Brasil, estabelecido pelas bandeiras e adquirentes. Crédito parcelado tem liquidação em múltiplos de 30 dias por parcela. Débito e pré-pago liquidam em D+2. Pix liquida em tempo real, sem float."}),`
`,a.jsx(e.p,{children:a.jsx(e.strong,{children:"O float pode substituir o intercâmbio como receita principal?"})}),`
`,a.jsx(e.p,{children:"Em operações muito grandes de crédito com D+28, o float pode se aproximar de 30% a 50% da receita do intercâmbio. Dificilmente substitui, mas é uma fonte complementar relevante. Em operações de débito e pré-pago, o float é marginal."}),`
`,a.jsx(e.p,{children:a.jsx(e.strong,{children:"Operações com Pix geram float?"})}),`
`,a.jsx(e.p,{children:"Pix liquida em tempo real (segundos). O float gerado por transação Pix é desprezível. Em operações que combinam Pix e cartão, o float vem quase inteiramente do lado cartão."}),`
`,a.jsx(e.p,{children:a.jsx(e.strong,{children:"Como calcular o float da minha operação?"})}),`
`,a.jsx(e.p,{children:"Fórmula simplificada: TPV mensal × (prazo médio de liquidação em dias / 30 dias) × (Selic anual / 12). Ajuste conforme o percentual de saldo que efetivamente permanece em custódia (depende da estrutura contratual)."}),`
`,a.jsx(e.p,{children:a.jsx(e.strong,{children:"O que acontece se o BaaS não repassar o float?"})}),`
`,a.jsx(e.p,{children:"Você está deixando receita legítima na mesa. Em operações pequenas, o valor pode ser marginal. Em operações grandes, pode ser centenas de milhares de reais por ano. Sempre formalize a cláusula de repasse antes de assinar o contrato com o BaaS."}),`
`,a.jsx(e.h2,{id:"próximo-passo",children:a.jsx(e.a,{href:"#próximo-passo",children:"Próximo passo"})}),`
